import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it("should return empty grid when given empty grid", () => {
    expect(nextGeneration([])).toEqual([]);
  });
  it("should kill a single living cell (underpopulation)", () => {
    expect(nextGeneration([[0, 0]])).toEqual([]);
  });
  it("should kill two adjacent cells that each have only one neighbor", () => {
    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
  });
  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
    const sorted = result.map(c => c.join(",")).sort();
    expect(sorted).toEqual(["0,0", "0,1", "1,0", "1,1"]);
  });
  it.todo("should keep a live cell alive when it has exactly 2 live neighbors (survival)");
  it.todo("should keep a live cell alive when it has exactly 3 live neighbors (survival)");
  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
  it.todo("should produce a block still life from a block pattern");
  it.todo("should produce correct next generation for a blinker oscillator");
});

